module RefModule(
    COUT,
    SUM,
    A,
    B,
    CI
);output COUT;
    output SUM;
    input  A;
    input  B;
    input  CI;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    // Use a behavioral description for the full adder
    wire __SUM_tmp = A ^ B ^ CI;
    assign SUM = __SUM_tmp; // Sum calculation
    assign COUT = (A & B) | (B & CI) | (A & CI); // Carry-out calculation

endmodule
